linux.services_details.command:
python3 -c "import json,subprocess
try:
    out=subprocess.check_output(['systemctl','list-units','--type=service','--all','--no-pager','--no-legend'],stderr=subprocess.DEVNULL).decode()
    rows=[]
    for l in out.strip().split('\n')[:100]:
        p=l.strip().lstrip(chr(9679)).split(None,4)
        if len(p)>=4:
            rows.append({'unit':p[0],'load_state':p[1],'active_state':p[2],'sub_state':p[3],'description':p[4].strip() if len(p)>4 else ''})
    print(json.dumps(rows if rows else []))
except:
    print(json.dumps([]))"

linux.failed_logins.command:
python3 -c "import json,subprocess,datetime
since=(datetime.datetime.now()-datetime.timedelta(hours=1)).strftime('%Y-%m-%d %H:%M:%S')
failed=0
try:
    out=subprocess.run(['journalctl','--since',since,'--no-pager','--quiet','-u','ssh','-u','sshd'],capture_output=True,text=True,timeout=15).stdout
    failed=sum(1 for l in out.split('\n') if 'Failed password' in l or 'Invalid user' in l or 'authentication failure' in l.lower())
except:
    try:
        out=open('/var/log/auth.log').read()
        failed=sum(1 for l in out.split('\n') if 'Failed password' in l or 'Invalid user' in l)
    except:
        failed=-1
print(json.dumps({'failed_login_count':failed}))"

linux.system_info.command:
python3 -c "import json,subprocess
try:
    os_r={l.split('=',1)[0].strip():l.split('=',1)[1].strip().strip('\"') for l in open('/etc/os-release') if '=' in l}
    os_name=os_r.get('PRETTY_NAME',os_r.get('NAME','Unknown'))
    os_id=os_r.get('ID','unknown')
    os_version=os_r.get('VERSION_ID','')
    os_codename=os_r.get('VERSION_CODENAME','')
except:
    os_name='Unknown';os_id='unknown';os_version='';os_codename=''
kernel=subprocess.check_output(['uname','-r'],stderr=subprocess.DEVNULL).decode().strip()
arch=subprocess.check_output(['uname','-m'],stderr=subprocess.DEVNULL).decode().strip()
try:
    hostname=subprocess.check_output(['hostname','-f'],stderr=subprocess.DEVNULL).decode().strip()
except:
    hostname=subprocess.check_output(['hostname'],stderr=subprocess.DEVNULL).decode().strip()
m={l.split(':')[0].strip():int(l.split()[1])*1024 for l in open('/proc/meminfo') if ':' in l and len(l.split())>=2 and l.split()[1].isdigit()}
cores=sum(1 for l in open('/proc/cpuinfo') if l.startswith('processor'))
up_days=round(float(open('/proc/uptime').read().split()[0])/86400,1)
print(json.dumps({'hostname':hostname,'os_name':os_name,'os_id':os_id,'os_version':os_version,'os_codename':os_codename,'kernel_version':kernel,'architecture':arch,'total_memory_gb':round(m.get('MemTotal',0)/1024**3,1),'cpu_cores':cores,'uptime_days':up_days}))"
